import {
  ChangeDetectorRef,
  Component,
  computed,
  inject,
  signal,
  output,
  DestroyRef,
} from '@angular/core';
import { takeUntilDestroyed, toObservable } from '@angular/core/rxjs-interop';
import { DialogModule } from 'primeng/dialog';
import { TableLazyLoadEvent } from 'primeng/table';

import { combineLatest, of } from 'rxjs';
import {
  catchError,
  distinctUntilChanged,
  switchMap,
  tap,
} from 'rxjs/operators';

import {
  ClientListItem,
  ClientResponse,
  ClientsService,
} from '../../../../api';
import { AuthDataService } from '../../../../core/services/auth-data.service';
import { UtilityService } from '../../../../core/services/utility.service';
import { ClientDataService } from '../../services/client-data.service';
import { DEFAULT_PAGE_SIZE } from '../../../../core/models';
import { ClientSelectionFormComponent } from '../../../../shared/components/client-selection-form/client-selection-form.component';

import { BroadcastMessageService } from '../../../../core/services/message.service';
import { ActionType } from '../../../../core/models/message.model';
import { RecentClientsService } from '../../../../shared/services/recent-clients.service';
import { isString, isDefined, hasProperty } from '../../../../shared/utils';

@Component({
  selector: 'app-client-switcher',
  imports: [DialogModule, ClientSelectionFormComponent],
  templateUrl: './client-switcher.component.html',
  styleUrls: ['./client-switcher.component.scss'],
})
export class ClientSwitcherComponent {
  private readonly messageService = inject(BroadcastMessageService);
  private readonly destroyRef = inject(DestroyRef);
  private readonly recentClientsService = inject(RecentClientsService);
  private readonly authDataService = inject(AuthDataService);
  private readonly utilityService = inject(UtilityService);
  private readonly clientDataService = inject(ClientDataService);
  private readonly clientsService = inject(ClientsService);
  private readonly cdr = inject(ChangeDetectorRef);

  readonly onClosed = output<void>();

  display = signal<boolean>(true);
  clients = signal<ClientListItem[]>([]);
  totalRecords = signal<number>(0);
  loading = signal<boolean>(false);

  // Track the unfiltered total count to determine search mode
  private readonly unfilteredTotalCount = signal<number>(0);
  searchTerm = signal<string>('');
  paginationOffset = signal<number>(0);

  // Determine if we should use server-side search based on unfiltered total count
  useServerSearch = computed(
    () => this.unfilteredTotalCount() >= DEFAULT_PAGE_SIZE,
  );

  // Expose recent clients from the service for the template
  recentClients = this.recentClientsService.recentClients;

  constructor() {
    this.setupClientsStream();
  }

  private setupClientsStream(): void {
    const search$ = toObservable(this.searchTerm).pipe(distinctUntilChanged());
    const offset$ = toObservable(this.paginationOffset).pipe(
      distinctUntilChanged(),
    );

    combineLatest([search$, offset$])
      .pipe(
        takeUntilDestroyed(this.destroyRef),
        tap(() => this.loading.set(true)),
        switchMap(([searchTerm, offset]) => {
          const userProfile = this.authDataService.getUserProfile();
          if (!isDefined(userProfile?.owner?.id)) {
            return of(null);
          }

          const ownerId =
            userProfile.owner.type === 'client'
              ? this.clientDataService.getSelectedClient()?.id
              : userProfile.owner.id;

          if (!isDefined(ownerId)) {
            return of(null);
          }

          const filters: Record<
            string,
            string | { value: string; operator: string }
          > = {
            state: {
              value: 'active',
              operator: '=',
            },
          };

          if (isString(searchTerm) && searchTerm.trim().length > 0) {
            filters['name'] = {
              value: `*${searchTerm}*`,
              operator: '=',
            };
          }

          const rqlFilter = this.utilityService.constructRqlFilter(filters);

          return this.clientsService
            .listClients(
              ownerId,
              offset,
              DEFAULT_PAGE_SIZE,
              'name:asc',
              rqlFilter,
            )
            .pipe(
              catchError((error) => {
                console.error('Failed to load clients:', error);
                return of(null);
              }),
            );
        }),
      )
      .subscribe((data) => {
        if (
          isDefined(data) &&
          hasProperty(data, 'items') &&
          hasProperty(data, 'count')
        ) {
          const items = data.items ?? [];
          this.clients.set(items);
          this.totalRecords.set(data.count);

          // Only update unfiltered count when not searching and on first page
          if (
            this.searchTerm().trim() === '' &&
            this.paginationOffset() === 0
          ) {
            this.unfilteredTotalCount.set(data.count ?? items.length);
          }
        }
        this.loading.set(false);
        this.cdr.detectChanges();
      });
  }

  onClientSearch(searchTerm: string): void {
    this.paginationOffset.set(0);
    this.searchTerm.set(searchTerm);
  }

  onLazyLoadClients(event: TableLazyLoadEvent): void {
    this.paginationOffset.set(event.first ?? 0);
  }

  selectClient(clientId: string): void {
    if (!clientId) return;

    // Broadcast profile_changed event to flutter
    this.messageService.sendAction(ActionType.profile_changed, {
      clientId: clientId,
    });

    this.clientsService
      .getClient(clientId)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: (response: ClientResponse) => {
          this.clientDataService.setSelectedClient(response);
          // Add selected client to recently used list
          if (isDefined(response.name)) {
            this.recentClientsService.addRecentClient(
              response.id,
              response.name,
            );
          }
          // Close dialog after successfully setting the client
          // This must happen after setSelectedClient to prevent component destruction
          // from cancelling the subscription via takeUntilDestroyed
          this.closeDialog();
        },
        error: (error) => {
          console.error('Failed to select client:', error);
          // Still close the dialog on error to provide user feedback
          this.closeDialog();
        },
      });
  }

  closeDialog(): void {
    this.display.set(false);
    this.onClosed.emit();
  }

  openDialog(): void {
    this.display.set(true);
    this.paginationOffset.set(0);
    this.searchTerm.set('');
  }
}
