import { Component, input } from '@angular/core';
import { CommonModule } from '@angular/common';
import { TableModule } from 'primeng/table';
import { TagModule } from 'primeng/tag';
import { InputTextModule } from 'primeng/inputtext';
import { FormsModule } from '@angular/forms';

export interface FeatureAccessRow {
  featureId: string;
  label: string;
  hasAccess: boolean;
  permissions?: string;
}

@Component({
  selector: 'app-qa-feature-access-table',
  imports: [CommonModule, TableModule, TagModule, InputTextModule, FormsModule],
  templateUrl: './qa-feature-access-table.component.html',
  styleUrls: ['./qa-feature-access-table.component.scss'],
})
export class QaFeatureAccessTableComponent {
  rows = input.required<FeatureAccessRow[]>();
  context = input.required<string>();

  searchTerm = '';

  get filteredRows(): FeatureAccessRow[] {
    if (!this.searchTerm) return this.rows();
    const term = this.searchTerm.toLowerCase();
    return this.rows().filter(
      (r) =>
        r.featureId.toLowerCase().includes(term) ||
        r.label.toLowerCase().includes(term) ||
        (r.permissions ?? '').toLowerCase().includes(term),
    );
  }

  get accessibleCount(): number {
    return this.rows().filter((r) => r.hasAccess).length;
  }

  get restrictedCount(): number {
    return this.rows().filter((r) => !r.hasAccess).length;
  }

  /**
   * Get severity for tag based on access
   */
  getAccessSeverity(hasAccess: boolean): 'success' | 'danger' {
    return hasAccess ? 'success' : 'danger';
  }
}
