/**
 * SmartPayloadBuilder - Generates dummy data based on property name heuristics.
 * This avoids manual mapping for every single API endpoint.
 */
import {
  ApiSimulationEntry,
  SimulationOperation,
} from './api-simulation.registry';
export class SmartPayloadBuilder {
  /**
   * Generates a dummy object based on a list of field names.
   * If field names are not available, it returns a generic object.
   */
  static generateForFields(fields: string[]): Record<string, unknown> {
    const payload: Record<string, unknown> = {};

    fields.forEach((field) => {
      payload[field] = this.getValueForField(field);
    });

    return payload;
  }

  /**
   * Heuristic logic to determine the value of a field based on its name.
   */
  private static getValueForField(name: string): unknown {
    const lowered = name.toLowerCase();

    // IDs and UUIDs
    if (lowered === 'id' || lowered.endsWith('id')) {
      return '3fa85f64-5717-4562-b3fc-2c963f66afa6';
    }

    // Names and Titles
    if (lowered.includes('name') || lowered.includes('title')) {
      return `Test ${name.charAt(0).toUpperCase() + name.slice(1)}`;
    }

    // Emails
    if (lowered.includes('email')) {
      return 'test@example.com';
    }

    // Descriptions and Comments
    if (
      lowered.includes('description') ||
      lowered.includes('comment') ||
      lowered.includes('note')
    ) {
      return 'This is a test generated payload for verification purposes.';
    }

    // Numbers, Amounts, Counts
    if (
      lowered.includes('amount') ||
      lowered.includes('count') ||
      lowered.includes('price') ||
      lowered.includes('total')
    ) {
      return 100;
    }

    // Booleans
    if (
      lowered.startsWith('is') ||
      lowered.startsWith('has') ||
      lowered.startsWith('should') ||
      lowered.includes('active') ||
      lowered.includes('enabled')
    ) {
      return true;
    }

    // Dates
    if (
      lowered.includes('date') ||
      lowered.includes('time') ||
      lowered.endsWith('at')
    ) {
      return new Date().toISOString();
    }

    // Enums / Statuses
    if (lowered.includes('status') || lowered.includes('type')) {
      return 'ACTIVE';
    }

    // URLs
    if (lowered.includes('url') || lowered.includes('link')) {
      return 'https://example.com';
    }

    // Default fallback
    return 'test_value';
  }

  /**
   * Helper to get common dummy objects for specific well-known endpoints
   * until the backend can provide property lists for all mappings.
   */
  static getPayloadForEndpoint(endpoint: string, method: string): unknown {
    if (method.toUpperCase() === 'GET' || method.toUpperCase() === 'DELETE') {
      return null;
    }

    // Common entity patterns
    if (endpoint.includes('/assets')) {
      return this.generateForFields([
        'name',
        'description',
        'categoryId',
        'ownerId',
      ]);
    }
    if (endpoint.includes('/users')) {
      return this.generateForFields([
        'firstName',
        'lastName',
        'email',
        'roleId',
      ]);
    }
    if (endpoint.includes('/clients') || endpoint.includes('/vendors')) {
      return this.generateForFields([
        'name',
        'email',
        'phoneNumber',
        'address',
      ]);
    }

    // Generic fallback if we don't know the fields yet
    return { name: 'Test Entity', description: 'Generated by QA Tool' };
  }

  /**
   * Generates a contract-aware payload using the API simulation registry.
   */
  static generateFromRegistry(
    entry: ApiSimulationEntry,
    operation: SimulationOperation,
    providedOwnerId?: string,
  ): Record<string, unknown> | null {
    if (operation === 'delete') {
      return null;
    }

    const fields =
      operation === 'create' ? entry.createFields : entry.updateFields;
    const payload = this.generateForFields(fields);

    // Provide the actual ownerId if requested and needed
    if (
      operation === 'create' &&
      entry.requiresOwnerId &&
      providedOwnerId !== undefined &&
      providedOwnerId !== ''
    ) {
      payload['ownerId'] = providedOwnerId;
    }

    // Usually updates exclude the ownerId on DTOs, but let's be explicit
    if (operation === 'update' && payload['ownerId'] !== undefined) {
      delete payload['ownerId'];
    }

    return payload;
  }
}
