import { Pipe, PipeTransform } from '@angular/core';
import { isNullOrUndefined } from '../../../../shared/utils';

interface SmallCapsSegment {
  letter: string;
  isCapital: boolean;
  isSpace: boolean;
}

/**
 * Transforms text into small caps format with each word's first letter enlarged.
 * @example
 * {{ 'Customer Configuration' | smallCaps }}
 * Returns array with segments marking capital letters, rest, and spaces
 */
@Pipe({
  name: 'smallCaps',
})
export class SmallCapsPipe implements PipeTransform {
  transform(value: string | null | undefined): SmallCapsSegment[] {
    if (isNullOrUndefined(value) || value === '') {
      return [];
    }

    const text = String(value).toUpperCase();
    const segments: SmallCapsSegment[] = [];

    const parts = text.split(/(\s+|[^A-Z0-9\s]+)/);

    for (const part of parts) {
      if (!part) continue;

      if (part.trim() === '') {
        // It's a space or multiple spaces
        for (const char of part) {
          segments.push({ letter: char, isCapital: false, isSpace: true });
        }
        continue;
      }

      // Check if it's alphanumeric
      if (/^[A-Z0-9]+$/.test(part)) {
        // Enlarge the first character
        segments.push({ letter: part[0], isCapital: true, isSpace: false });
        if (part.length > 1) {
          segments.push({
            letter: part.slice(1),
            isCapital: false,
            isSpace: false,
          });
        }
      } else {
        // It's non-alphanumeric (punctuations etc.)
        segments.push({ letter: part, isCapital: false, isSpace: false });
      }
    }

    return segments;
  }
}
