import { Component, input, output, model } from '@angular/core';
import { CommonModule } from '@angular/common';
import { QaTestModeBannerComponent } from '../qa-test-mode-banner/qa-test-mode-banner.component';
import { QaPersonaSelectorComponent } from '../qa-persona-selector/qa-persona-selector.component';
import { QaPermissionTogglesComponent } from '../qa-permission-toggles/qa-permission-toggles.component';
import { QaFeatureAccessStatsComponent } from '../qa-feature-access-stats/qa-feature-access-stats.component';
import {
  QaFeatureAccessTableComponent,
  FeatureAccessRow,
} from '../qa-feature-access-table/qa-feature-access-table.component';
import { UserRoleListItem } from '../../../../../api';
import {
  FeatureAccessStats,
  CanViewContextFn,
} from '../../models/qa-tester.models';

@Component({
  selector: 'app-qa-simulation-tab',
  imports: [
    CommonModule,
    QaTestModeBannerComponent,
    QaPersonaSelectorComponent,
    QaPermissionTogglesComponent,
    QaFeatureAccessStatsComponent,
    QaFeatureAccessTableComponent,
  ],
  templateUrl: './qa-simulation-tab.component.html',
})
export class QaSimulationTabComponent {
  // Inputs
  testMode = input.required<boolean>();
  activeProfileName = input.required<string>();
  isSaving = input<boolean>(false);
  roles = input.required<UserRoleListItem[]>();
  togglePermissions = input.required<string[]>();
  checkPermission = input.required<(perm: string) => boolean>();
  clientStats = input.required<FeatureAccessStats>();
  vendorStats = input.required<FeatureAccessStats>();
  distributorStats = input.required<FeatureAccessStats>();
  canViewContext = input.required<CanViewContextFn>();

  // Feature access rows per tier
  clientFeatureAccess = input<FeatureAccessRow[]>([]);
  vendorFeatureAccess = input<FeatureAccessRow[]>([]);
  distributorFeatureAccess = input<FeatureAccessRow[]>([]);

  // Model
  selectedProfileId = model<string | null>(null);

  // Outputs
  saveRequested = output<void>();
  resetRequested = output<void>();
  applyProfileRequested = output<void>();
  togglePermissionRequested = output<{
    permission: string;
    enabled: boolean;
  }>();
}
