import { Component, computed, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ButtonModule } from 'primeng/button';
import { TagModule } from 'primeng/tag';
import { TableModule } from 'primeng/table';
import { DialogModule } from 'primeng/dialog';
import { TooltipModule } from 'primeng/tooltip';

import {
  ApiSimulationEntry,
  SimulationOperation,
} from '../../../../utils/api-simulation.registry';
import {
  ApiSimulationService,
  SimulationResult,
} from '../../../../../core/services/api-simulation.service';
import { AuthDataService } from '../../../../../core/services/auth-data.service';

@Component({
  selector: 'app-qa-api-simulation-panel',
  imports: [
    CommonModule,
    ButtonModule,
    TagModule,
    TableModule,
    DialogModule,
    TooltipModule,
  ],
  templateUrl: './qa-api-simulation-panel.component.html',
})
export class QaApiSimulationPanelComponent {
  private readonly simulationService = inject(ApiSimulationService);
  private readonly authData = inject(AuthDataService);

  isVerifying = signal<boolean>(false);
  results = signal<SimulationResult[]>([]);
  selectedResult = signal<SimulationResult | null>(null);

  readonly availableApis = computed(() => {
    // Uses real user permissions (not simulated) via the service
    return this.simulationService.getSimulatableApis();
  });

  readonly stats = computed(() => {
    const res = this.results();
    const matches = res.filter(
      (r) =>
        r.backendAccess !== 'Pending' && r.frontendExpected === r.backendAccess,
    );
    const mismatches = res.filter(
      (r) =>
        r.backendAccess !== 'Pending' &&
        r.backendAccess !== 'Error' &&
        r.frontendExpected !== r.backendAccess,
    );
    return {
      total: res.length,
      allowed: res.filter((r) => r.backendAccess === 'Allowed').length,
      forbidden: res.filter((r) => r.backendAccess === 'Forbidden').length,
      errors: res.filter((r) => r.backendAccess === 'Error').length,
      matches: matches.length,
      mismatches: mismatches.length,
    };
  });

  /** PrimeNG severity tag for backend access status */
  getAccessSeverity(
    access: string,
  ): 'success' | 'danger' | 'warn' | 'info' | 'secondary' {
    if (access === 'Allowed') return 'success';
    if (access === 'Forbidden') return 'danger';
    if (access === 'Error') return 'warn';
    if (access === 'Pending') return 'secondary';
    return 'info';
  }

  /** Returns true when frontend expectation ≠ backend result (a mismatch) */
  isMismatch(result: SimulationResult): boolean {
    return (
      result.backendAccess !== 'Pending' &&
      result.backendAccess !== 'Error' &&
      result.frontendExpected !== result.backendAccess
    );
  }

  async runAllVerifications() {
    this.isVerifying.set(true);
    this.results.set([]);

    const apis = this.availableApis();
    const ownerId = this.authData.getUserOwnerId() ?? '';

    try {
      await this.simulationService.verifyMultiple(apis, ownerId, (result) => {
        this.results.update((curr) => [...curr, result]);
      });
    } finally {
      this.isVerifying.set(false);
    }
  }

  async runSingleVerification(entry: ApiSimulationEntry) {
    this.isVerifying.set(true);

    // Remove previous results for this entry
    this.results.update((curr) => curr.filter((r) => r.entry.id !== entry.id));

    const ownerId = this.authData.getUserOwnerId() ?? '';

    try {
      await this.simulationService.verifyMultiple(
        [entry],
        ownerId,
        (result) => {
          this.results.update((curr) => [...curr, result]);
        },
      );
    } finally {
      this.isVerifying.set(false);
    }
  }

  getResultFor(
    entryId: string,
    operation: SimulationOperation,
  ): SimulationResult | undefined {
    return this.results().find(
      (r) => r.entry.id === entryId && r.operation === operation,
    );
  }

  showDetails(result: SimulationResult) {
    this.selectedResult.set(result);
  }
}
