import { Injectable } from '@angular/core';
import { Subject } from 'rxjs';

export type RefreshTokenState =
  | { status: 'idle' }
  | { status: 'refreshing' }
  | { status: 'success'; token: string }
  | { status: 'error'; error: Error };

@Injectable({
  providedIn: 'root',
})
export class TokenRefreshCoordinatorService {
  refreshTokenInProgress = false;
  refreshTokenSubject = new Subject<RefreshTokenState>();

  resetRefreshState(): void {
    this.refreshTokenInProgress = false;
  }

  notifyRefreshSuccess(token: string): void {
    this.refreshTokenSubject.next({ status: 'success', token });
  }

  notifyRefreshError(error: Error): void {
    this.refreshTokenSubject.next({ status: 'error', error });
  }

  startRefresh(): void {
    this.refreshTokenInProgress = true;
    this.refreshTokenSubject.next({ status: 'refreshing' });
  }
}
