import { Routes } from '@angular/router';
import { authGuard } from './core/guards/auth.guard';
import { featureGuard } from './core/guards/feature.guard';
import { MainLayoutComponent } from './layouts/components/main-layout/main-layout.component';
import { userProfileResolver } from './core/resolvers/user-profile.resolver';
import { ExternalTabComponent } from './features/external-tab/external-tab.component';
import { clientSelectedGuard } from './core/guards/client-selected.guard';
import { adminPermissionsGuard } from './core/guards';

export const routes: Routes = [
  {
    path: '',
    component: MainLayoutComponent,
    canActivate: [authGuard, clientSelectedGuard],
    resolve: {
      userProfile: userProfileResolver,
    },
    children: [
      {
        path: '',
        redirectTo: 'position',
        pathMatch: 'full',
      },
      {
        path: 'position',
        data: { isFlutterRoute: true },
        loadChildren: () =>
          import('./features/position/position.routes').then(
            (m) => m.POSITION_ROUTES,
          ),
      },
      {
        path: 'alerts',
        data: { isFlutterRoute: true, featureFlag: 'page.alerts.enabled' },
        canActivate: [featureGuard],
        loadChildren: () =>
          import('./features/alerts/alerts.routes').then(
            (m) => m.ALERTS_ROUTES,
          ),
      },
      {
        path: 'media',
        data: { isFlutterRoute: true, featureFlag: 'page.videos.enabled' },
        canActivate: [featureGuard],
        loadChildren: () =>
          import('./features/media/media.routes').then((m) => m.MEDIA_ROUTES),
      },
      {
        path: 'history',
        data: { isFlutterRoute: true, featureFlag: 'page.replay.enabled' },
        canActivate: [featureGuard],
        loadChildren: () =>
          import('./features/history/history.routes').then(
            (m) => m.HISTORY_ROUTES,
          ),
      },
      {
        path: 'user',
        loadChildren: () =>
          import('./features/users/users.routes').then((m) => m.USERS_ROUTES),
      },
      {
        path: 'admin',
        canActivate: [adminPermissionsGuard],
        loadChildren: () =>
          import('./features/administration/administration.routes').then(
            (m) => m.ADMINISTRATION_ROUTES,
          ),
      },
      {
        path: 'analytical-report',
        loadComponent: () =>
          import(
            './features/development/components/analytical-report/analytical-report.component'
          ).then((m) => m.AnalyticalReportComponent),
      },
      {
        path: 'app-store',
        data: { featureFlag: 'page.moreapps.enabled' },
        canActivate: [featureGuard],
        loadChildren: () =>
          import('./features/app-store/app-store.routes').then(
            (m) => m.APP_STORE_ROUTES,
          ),
      },
      {
        path: 'development',
        loadChildren: () =>
          import('./features/development/development.routes').then(
            (m) => m.DEVELOPMENT_ROUTES,
          ),
      },
      {
        path: 'external/:id',
        component: ExternalTabComponent,
      },
    ],
  },
  {
    path: 'auth',
    loadChildren: () =>
      import('./features/auth/auth.routes').then((m) => m.AUTH_ROUTES),
  },
  {
    path: 'unauthorized',
    loadComponent: () =>
      import('./shared/components/unauthorized/unauthorized.component').then(
        (m) => m.UnauthorizedComponent,
      ),
  },
];
