import { inject, Injectable } from '@angular/core';
import { HttpClient, HttpContext, HttpHeaders } from '@angular/common/http';
import { firstValueFrom } from 'rxjs';

import { AuthDataService } from './auth-data.service';
import { SILENT_ERROR } from '../models/http-context.constants';
import { isNullOrUndefined } from '../../shared/utils';
import { OwnerType } from '../models/permission.model';
import { SmartPayloadBuilder } from '../../shared/utils/dummy-data-generators';
import { Configuration } from '../../api';

export interface ApiVerificationResult {
  endpoint: string;
  method: string;
  permission: string;
  frontendExpected: boolean;
  backendAccess: 'Allowed' | 'Forbidden' | 'Error';
  errorDetails?: string;
  requestBody?: unknown;
}

export interface PermissionMapping {
  method: string;
  endpoint: string;
  permission: string;
}

@Injectable({
  providedIn: 'root',
})
export class ApiVerificationService {
  private readonly http = inject(HttpClient);
  private readonly authData = inject(AuthDataService);
  private readonly apiConfig = inject(Configuration);

  /**
   * Fetches the canonical permission mapping from the backend.
   */
  async getPermissionMapping(): Promise<PermissionMapping[]> {
    try {
      const url = `${this.apiConfig.basePath}/permissions/mapping`;
      return await firstValueFrom(
        this.http.get<PermissionMapping[]>(url, {
          context: new HttpContext().set(SILENT_ERROR, true),
        }),
      );
    } catch (error) {
      console.error('Failed to fetch permission mapping:', error);
      // Fallback to a few critical ones if endpoint doesn't exist yet
      return [
        {
          method: 'GET',
          endpoint: '/entities/assets',
          permission: 'asset:list',
        },
        {
          method: 'POST',
          endpoint: '/entities/assets',
          permission: 'asset:create',
        },
        { method: 'GET', endpoint: '/accounts/users', permission: 'user:list' },
      ];
    }
  }

  /**
   * Runs a suite of backend enforcement checks scoped to a hierarchical level.
   * @param targetOwnerId Optional ID of the owner to test against.
   * @param targetOwnerType The hierarchical level being tested (client, vendor, distributor).
   */
  async verifyBackEndEnforcement(
    targetOwnerId?: string,
    targetOwnerType?: OwnerType,
  ): Promise<ApiVerificationResult[]> {
    const ownerId = targetOwnerId ?? this.authData.getUserOwnerId();
    const ownerType = (targetOwnerType ??
      this.authData.getUserOwnerType()) as OwnerType;

    if (isNullOrUndefined(ownerId) || isNullOrUndefined(ownerType)) {
      return [];
    }

    const mapping = await this.getPermissionMapping();
    const results: ApiVerificationResult[] = [];

    // Run tests sequentially to avoid flooding
    for (const entry of mapping) {
      const result = await this.executeTestCase(entry, ownerId);
      results.push(result);
    }

    return results;
  }

  /**
   * Executes a single API verification test case.
   */
  private async executeTestCase(
    mapping: PermissionMapping,
    ownerId: string,
  ): Promise<ApiVerificationResult> {
    const { method, endpoint, permission } = mapping;

    // Substitute path parameters
    const processedEndpoint = endpoint
      .replace('{id}', ownerId)
      .replace(':id', ownerId)
      .replace('{ownerId}', ownerId);

    const url = `${this.apiConfig.basePath}${processedEndpoint.startsWith('/') ? '' : '/'}${processedEndpoint}`;

    // Use SmartPayloadBuilder for bodies
    const body = SmartPayloadBuilder.getPayloadForEndpoint(endpoint, method);

    // Set headers, including the bypass header
    const headers = new HttpHeaders({
      'x-auth-testing': 'true',
    });

    const context = new HttpContext().set(SILENT_ERROR, true);

    try {
      const options = { headers, context };

      switch (method.toUpperCase()) {
        case 'GET': {
          const separator = url.includes('?') ? '&' : '?';
          const getUrl = `${url}${separator}limit=1&owner=${ownerId}`;
          await firstValueFrom(this.http.get(getUrl, options));
          break;
        }
        case 'POST':
          await firstValueFrom(this.http.post(url, body, options));
          break;
        case 'PUT':
          await firstValueFrom(this.http.put(url, body, options));
          break;
        case 'DELETE':
          await firstValueFrom(this.http.delete(url, options));
          break;
        case 'PATCH':
          await firstValueFrom(this.http.patch(url, body, options));
          break;
        default:
          throw new Error(`Unsupported method: ${method}`);
      }

      return {
        endpoint,
        method,
        permission,
        frontendExpected: this.authData.hasRealPermission(permission),
        backendAccess: 'Allowed',
        requestBody: body,
      };
    } catch (err: unknown) {
      const error = err as {
        status?: number;
        statusText?: string;
        message?: string;
      };
      const isForbidden = error.status === 403 || error.status === 401;
      return {
        endpoint,
        method,
        permission,
        frontendExpected: this.authData.hasRealPermission(permission),
        backendAccess: isForbidden ? 'Forbidden' : 'Error',
        errorDetails:
          (error.statusText ?? '') || (error.message ?? '') || 'Unknown Error',
        requestBody: body,
      };
    }
  }
}
