import { Component, input, output, model } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { SelectModule } from 'primeng/select';
import { ButtonModule } from 'primeng/button';
import { CardModule } from 'primeng/card';
import { TagModule } from 'primeng/tag';

import { UserRoleListItem } from '../../../../../api';

@Component({
  selector: 'app-qa-persona-selector',
  imports: [
    CommonModule,
    FormsModule,
    SelectModule,
    ButtonModule,
    CardModule,
    TagModule,
  ],
  templateUrl: './qa-persona-selector.component.html',
})
export class QaPersonaSelectorComponent {
  roles = input.required<UserRoleListItem[]>();
  selectedProfileId = model<string | null>(null);

  apply = output<void>();

  getProfileColorClass(color: string): string {
    const colorMap: Record<string, string> = {
      green: 'bg-green-500',
      blue: 'bg-blue-500',
      orange: 'bg-orange-500',
      red: 'bg-red-500',
      purple: 'bg-purple-500',
      gray: 'bg-gray-500',
    };
    return colorMap[color] || 'bg-gray-500';
  }
}
