import { Component, input, output } from '@angular/core';
import { CommonModule } from '@angular/common';
import { CardModule } from 'primeng/card';
import { TooltipModule } from 'primeng/tooltip';

@Component({
  selector: 'app-qa-permission-toggles',
  imports: [CommonModule, CardModule, TooltipModule],
  templateUrl: './qa-permission-toggles.component.html',
})
export class QaPermissionTogglesComponent {
  permissions = input.required<string[]>();
  checkPermission = input.required<(perm: string) => boolean>();
  togglePermission = output<{ permission: string; enabled: boolean }>();
}
