import { CommonModule } from '@angular/common';
import { Component, input } from '@angular/core';
import { RouterModule } from '@angular/router';
import { MenuItem } from 'primeng/api';
import { TooltipModule } from 'primeng/tooltip';
import { FontAwesomeModule } from '@fortawesome/angular-fontawesome';
import { SmallCapsPipe } from './small-caps.pipe';

@Component({
  selector: 'app-menu-item',
  imports: [
    RouterModule,
    CommonModule,
    TooltipModule,
    FontAwesomeModule,
    SmallCapsPipe,
  ],
  templateUrl: './menu-item.component.html',
  styleUrl: './menu-item.component.scss',
})
export class MenuItemComponent {
  readonly item = input<MenuItem>();
  readonly isCollapsed = input<boolean>(false);

  onItemClick(event: MouseEvent): void {
    const menuItem = this.item();
    const command = menuItem?.command;
    if (!command) {
      return;
    }

    // Stop event propagation to prevent PrimeNG from also handling this click
    event.stopPropagation();

    const hasRoute = Boolean(menuItem?.['routerLink'] ?? menuItem?.['route']);
    if (!hasRoute) {
      event.preventDefault();
    }

    command({ originalEvent: event, item: menuItem });
  }
}
