/**
 * API Simulation Registry
 *
 * Single source of truth for all APIs that support simulation.
 * Derived from OpenAPI-generated service/model contracts in src/app/api/.
 *
 * Rule: if a service has a `create*` method, it is registered here with
 * create + update + delete operations (aligning with the QA "create permission
 * implies modify/delete access" policy).
 */

export type SimulationOperation = 'list' | 'create' | 'update' | 'delete';

export interface ApiSimulationEntry {
  /** Internal ID for grouping and referencing */
  id: string;
  /** Human-readable module/domain name */
  domain: string;
  /** The specific entity name, e.g., 'Company Groups' */
  name: string;
  /** Base API endpoint (e.g., /entities/alerts) */
  basePath: string;
  /** Which CRUD operations are available on this endpoint */
  operations: SimulationOperation[];
  /** Permission required for create/update/delete (the primary permission). */
  permission: string;
  /** Permission required specifically for list/read access (e.g., 'asset:list') */
  listPermission?: string;
  /** Does the create payload require an ownerId? */
  requiresOwnerId: boolean;
  /** Which fields to populate for a CREATE request payload */
  createFields: string[];
  /** Which fields to populate for an UPDATE request payload */
  updateFields: string[];
}

