import { ErrorHandler, inject, Injectable } from '@angular/core';
import { VersionUpdateService } from './version-update.service';

@Injectable({
  providedIn: 'root',
})
export class GlobalErrorHandlerService implements ErrorHandler {
  private readonly versionUpdateService = inject(VersionUpdateService);

  constructor() {
    // Catch unhandled promise rejections (zoneless compatible)
    globalThis.addEventListener('unhandledrejection', (event) => {
      console.error('Unhandled promise rejection caught:', event.reason);
      this.handleError(event.reason);
      event.preventDefault();
    });

    // Also catch any global errors
    globalThis.addEventListener('error', (event) => {
      console.error('Global error event caught:', event.error);
      this.handleError(event.error);
    });
  }

  handleError(error: unknown): void {
    console.error('Global error handler invoked with:', error);

    // Check for version mismatch errors first
    if (this.versionUpdateService.isVersionMismatchError(error)) {
      console.log('Detected version mismatch error, triggering update flow');
      this.versionUpdateService.handleVersionMismatch('global error');
      return;
    }

    // Log other errors normally
    console.error('Unhandled application error:', error);
  }
}
