import {
  Component,
  HostListener,
  effect,
  inject,
  signal,
  computed,
} from '@angular/core';
import { hasProperty, isDefined, isString } from '../../../shared/utils';

import { ActionType } from '../../../core/models/message.model';
import { AuthDataService } from '../../../core/services/auth-data.service';
import { AvatarModule } from 'primeng/avatar';
import { BadgeModule } from 'primeng/badge';
import { BroadcastMessageService } from '../../../core/services/message.service';
import { ButtonModule } from 'primeng/button';
import { ClientDataService } from '../../../features/clients/services/client-data.service';
import { ClientSwitcherComponent } from '../../../features/clients/components/client-switcher/client-switcher.component';
import { ClientsService } from '../../../api';
import { CommonModule } from '@angular/common';
import { LayoutService } from '../../services/layout.service';
import { LocalStorageService } from '../../../shared/services/local-storage.service';
import {
  LOCAL_STORAGE_SIDEBAR_STATE_KEY,
  MOBILE_BREAKPOINT,
} from '../../../core/models';
import { MenuItem } from 'primeng/api';
import { MenuItemComponent } from './menu-item/menu-item.component';
import { MenuModule } from 'primeng/menu';
import { RippleModule } from 'primeng/ripple';
import { RouterModule } from '@angular/router';
import { ToggleButtonComponent } from './toggle-button/toggle-button.component';
import { TooltipModule } from 'primeng/tooltip';
import { UserProfileComponent } from './user-profile/user-profile.component';
import { UtilityService } from '../../../core/services/utility.service';
import { RecentClientsService } from '../../../shared/services/recent-clients.service';
import {
  NavigationService,
  NavigationGroup,
  NavigationItem,
} from '../../../core/services/navigation.service';
import { FontAwesomeModule } from '@fortawesome/angular-fontawesome';
import { UserSessionService } from '../../../core/services/user-session.service';
import { AccountSwitcherComponent } from '../../../features/accounts/components/account-switcher/account-switcher.component';
import { take } from 'rxjs';
import { DialogService } from 'primeng/dynamicdialog';
import { QAToolsService } from '../../../core/services/qa-tools.service';
import { QaPermissionTesterComponent } from '../../../shared/components/qa-permission-tester/qa-permission-tester.component';
import { environment } from '../../../../environments/environment';

@Component({
  selector: 'app-sidebar',
  imports: [
    BadgeModule,
    RippleModule,
    AvatarModule,
    MenuModule,
    CommonModule,
    ButtonModule,
    RouterModule,
    TooltipModule,
    ClientSwitcherComponent,
    MenuItemComponent,
    ToggleButtonComponent,
    UserProfileComponent,
    FontAwesomeModule,
    AccountSwitcherComponent,
  ],
  providers: [DialogService],
  templateUrl: './sidebar.component.html',
  styleUrls: ['./sidebar.component.scss'],
})
export class SidebarComponent {
  private readonly messageService = inject(BroadcastMessageService);

  private readonly authDataService = inject(AuthDataService);
  private readonly clientsService = inject(ClientsService);
  private readonly utilityService = inject(UtilityService);
  private readonly clientDataService = inject(ClientDataService);
  private readonly layoutService = inject(LayoutService);
  private readonly localStorageService = inject(LocalStorageService);
  private readonly navigationService = inject(NavigationService);
  private readonly userSessionService = inject(UserSessionService);
  private readonly recentClientsService = inject(RecentClientsService);
  private readonly dialogService = inject(DialogService);
  private readonly qaTools = inject(QAToolsService);

  // Computed menu items - automatically reactive to changes
  readonly topMenuItems = computed(() => {
    const groups = this.navigationService.getNavigationGroups();
    const menuItems = this.convertNavigationGroupsToMenuItems(groups);
    return this.addQaPermissionMenuItem(menuItems);
  });
  readonly bottomMenuItems = computed(() => {
    const recentClients = this.recentClientsService.recentClients();
    const selectedClient = this.selectedClientSignal();
    return this.createBottomMenuItems(recentClients, selectedClient?.id);
  });

  isCollapsed = signal(false);
  userProfileSignal = this.authDataService.getUserProfileSignal();
  selectedClientSignal = this.clientDataService.getSelectedClientSignal();
  clientLogo = signal<string | null>(null);
  isSwitchClient = signal(false);
  isSwitchAccount = signal(false);
  isMobile = signal(false);
  isSidebarOpen = signal(false);

  readonly canListClients = computed(() => {
    return (
      this.authDataService.hasPermission('client:list-clients') ||
      this.authDataService.hasPermission('clients:list')
    );
  });

  constructor() {
    this.reactToSelectedClientChanges();
    this.checkScreenSize();
  }

  @HostListener('window:resize')
  onResize(): void {
    this.checkScreenSize();
  }

  private getIconForItem(item: NavigationItem): string {
    const defaultPrimeIcon = 'pi pi-circle';
    const defaultFontAwesomeIcon = 'fas fa-question-circle';

    // Check if item.icon is defined and not null
    if (item.icon == null) {
      // Using == null to catch both undefined and null
      return defaultPrimeIcon;
    }

    if (typeof item.icon === 'string') {
      return item.icon;
    }

    // At this point, item.icon must be an IconDefinition if it's an object
    // No need for `item.icon !== null` check again if `item.icon == null` passed above
    // and typeof item.icon === 'object' is true
    if (typeof item.icon === 'object') {
      const faIcon = item.icon; // TypeScript infers this as IconDefinition here
      if (faIcon.prefix && faIcon.iconName) {
        return `${faIcon.prefix} fa-${faIcon.iconName}`;
      }
      return defaultFontAwesomeIcon;
    }

    return defaultPrimeIcon; // Fallback for any other unexpected type
  }

  private convertNavigationGroupsToMenuItems(
    groups: NavigationGroup[],
  ): MenuItem[] {
    const menuItems: MenuItem[] = [];
    for (const group of groups) {
      menuItems.push({
        label: group.name,
        items: group.items.map((item) =>
          this.convertNavigationItemToMenuItem(item),
        ),
        data: {
          groupId: group.id,
        },
      });
    }
    return menuItems;
  }

  private addQaPermissionMenuItem(menuItems: MenuItem[]): MenuItem[] {
    if (environment.production || !this.qaTools.isQAToolsAvailable()) {
      return menuItems;
    }

    const qaItem: MenuItem = {
      label: 'QA Permission Tester',
      icon: 'pi pi-shield',
      command: () => this.openQAPanel(),
    };

    const developmentGroup = menuItems.find(
      (item) => item?.['data']?.['groupId'] === 'development',
    );

    if (developmentGroup) {
      developmentGroup.items = [qaItem, ...(developmentGroup.items ?? [])];
      return menuItems;
    }

    return [
      ...menuItems,
      {
        label: 'Development',
        items: [qaItem],
        data: { groupId: 'development' },
      },
    ];
  }

  private convertNavigationItemToMenuItem(item: NavigationItem): MenuItem {
    const menuItem: MenuItem = {
      label: item.name,
      icon: this.getIconForItem(item),
      routerLink: item.route,

      data: {
        faIcon:
          typeof item.icon === 'object' && item.icon !== null
            ? item.icon
            : undefined,
        svgIcon:
          typeof item.icon === 'string' && item.icon.startsWith('svg:')
            ? item.icon.substring(4)
            : undefined,
      },
    };

    if (item.children && item.children.length > 0) {
      menuItem.items = item.children.map((child) =>
        this.convertNavigationItemToMenuItem(child),
      );
    }
    return menuItem;
  }

  setCollapsedFromLocalStorage(): void {
    const storedValue = this.localStorageService.getItem<boolean>(
      LOCAL_STORAGE_SIDEBAR_STATE_KEY,
    );
    const isSidebarVisible = storedValue ?? true;
    this.isCollapsed.set(!isSidebarVisible);
    this.layoutService.toggleSidebar(isSidebarVisible);
    if (this.isMobile()) {
      this.isSidebarOpen.set(isSidebarVisible);
      this.isCollapsed.set(false);
    }
  }

  checkScreenSize(): void {
    this.isMobile.set(window.innerWidth < MOBILE_BREAKPOINT);
    this.setCollapsedFromLocalStorage();
  }

  private reactToSelectedClientChanges(): void {
    // keep track of the last fetched client id to avoid duplicate requests
    let lastClientId: string | number | null = null;
    let lastUserId: string | null = null;

    effect(() => {
      const selectedClient = this.selectedClientSignal();
      const userProfile = this.userProfileSignal();

      const clientId = selectedClient?.id;
      const currentUserId = userProfile?.id ?? null;

      // If userId changed (user transition), reset tracking and clear logo
      if (currentUserId !== lastUserId) {
        lastUserId = currentUserId;
        lastClientId = null;
        this.clientLogo.set(null);

        // Don't proceed if there's no user (logged out state)
        if (currentUserId === null) {
          return;
        }
      }

      if (!isDefined(clientId)) {
        lastClientId = null;
        this.clientLogo.set(null);
        return;
      }

      if (clientId === lastClientId) {
        return;
      }

      lastClientId = clientId;

      // Make the HTTP request single-shot (take(1)) to avoid lingering subscriptions
      this.clientsService
        .getClientLogo(clientId)
        .pipe(take(1))
        .subscribe({
          next: (response: string | Blob | ArrayBuffer) => {
            // Handle different response types safely
            const blob =
              response instanceof Blob
                ? response
                : new Blob([response], {
                    type: 'application/octet-stream',
                  });

            this.utilityService
              .convertBlobToBase64(blob)
              .then((base64) => {
                this.clientLogo.set(base64);
              })
              .catch(() => {
                // swallow or log conversion errors as appropriate
              });
          },
          error: () => {
            // Optionally clear the logo or handle errors
            this.clientLogo.set(null);
          },
        });
    });
  }

  private createUserMenuItem(): MenuItem {
    const userProfile = this.userProfileSignal();
    const items: MenuItem[] = [];
    if (this.userSessionService.userSessions().length > 1) {
      items.push({
        label: 'Switch Account',
        icon: 'pi pi-arrow-right-arrow-left',
        command: () => this.toggleSwitchAccount(),
      });
    }
    items.push({
      label: 'Profile',
      icon: 'pi pi-user',
      route: '/user/profile',
    });

    return {
      label:
        isDefined(userProfile) &&
        hasProperty(userProfile, 'name') &&
        isString(userProfile.name)
          ? userProfile.name
          : 'User',
      items: items,
    };
  }

  private createBottomMenuItems(
    recentClients: { id: string; name: string }[] = [],
    selectedClientId?: string | number,
  ): MenuItem[] {
    // Build the Account Navigation items
    const accountNavigationItems: MenuItem[] = [];

    // Only add Clients menu item if user has permission
    if (this.canListClients()) {
      accountNavigationItems.push({
        label: 'Clients',
        icon: 'pi pi-search',
        command: () => this.toggleSwitchClient(),
      });
    }

    // Add recent clients (limited to 3, excluding currently selected client)
    const recentClientItems = recentClients
      .filter((client) => client.id !== selectedClientId?.toString())
      .slice(0, 3)
      .map((client) => ({
        label: client.name,
        icon: 'pi pi-clock',
        command: () => this.selectRecentClient(client.id),
      }));

    if (recentClientItems.length > 0) {
      accountNavigationItems.push(...recentClientItems);
    }

    // Add logout at the end
    accountNavigationItems.push({
      label: 'Logout',
      icon: 'pi pi-power-off',
      command: () => this.logout(),
    });

    return [
      this.createUserMenuItem(),
      {
        label: 'Account Navigation',
        items: accountNavigationItems,
      },
      { separator: true },
    ];
  }

  /**
   * Selects a client directly from the recent clients list in the sidebar.
   * @param clientId - The ID of the client to select
   */
  private selectRecentClient(clientId: string): void {
    this.clientDataService.setSelectedClientById(clientId).catch((error) => {
      console.error('Failed to select recent client:', error);
    });
  }

  toggleSidebar(): void {
    this.layoutService.toggleSidebar();
    this.isCollapsed.set(!this.isCollapsed());
    let newSidebarVisibilityState = !this.isCollapsed();
    if (this.isMobile()) {
      this.isSidebarOpen.set(!this.isSidebarOpen());
      newSidebarVisibilityState = this.isSidebarOpen();
      this.isCollapsed.set(false);
    }
    this.localStorageService.setItem(
      LOCAL_STORAGE_SIDEBAR_STATE_KEY,
      newSidebarVisibilityState,
    );
  }

  logout(): void {
    //send logout event to flutter
    this.messageService.sendAction(ActionType.logout, {}, 'Logging out');
    this.userSessionService.clearAllSessions();
    this.authDataService.logout();
  }

  toggleSwitchClient(): void {
    this.isSwitchClient.set(!this.isSwitchClient());
  }

  toggleSwitchAccount(): void {
    this.isSwitchAccount.set(!this.isSwitchAccount());
  }

  /**
   * Open the QA Permission Tester dialog
   */
  openQAPanel(): void {
    this.dialogService.open(QaPermissionTesterComponent, {
      header: 'QA Permission Tester',
      width: '90vw',
      height: '85vh',
      contentStyle: { overflow: 'auto', height: '100%' },
      baseZIndex: 10000,
      maximizable: true,
      modal: true,
      closable: true,
    });
  }
}
