import { inject, Injectable } from '@angular/core';
import {
  HttpClient,
  HttpContext,
  HttpErrorResponse,
  HttpHeaders,
} from '@angular/common/http';
import { firstValueFrom } from 'rxjs';

import { AuthDataService } from './auth-data.service';
import { Configuration } from '../../api';
import { SILENT_ERROR } from '../models/http-context.constants';
import {
  ApiSimulationEntry,
  API_SIMULATION_REGISTRY,
  SimulationOperation,
} from '../../shared/utils/api-simulation.registry';
import { SmartPayloadBuilder } from '../../shared/utils/dummy-data-generators';
import { PermissionUtils } from '../utils/permission.utils';

/**
 * Result of a single CRUD verification against the backend.
 *
 * The backend honors the `x-auth-testing: true` header by dry-running the
 * operation (no data is persisted) and returning:
 *   200 → user is allowed
 *   401/403 → user is forbidden
 */
export interface SimulationResult {
  entry: ApiSimulationEntry;
  operation: SimulationOperation;
  /** What the frontend permission simulation says the user should get */
  frontendExpected: 'Allowed' | 'Forbidden';
  /** What the backend actually returned */
  backendAccess: 'Allowed' | 'Forbidden' | 'Error' | 'Pending';
  /** Full URL that was hit */
  url: string;
  /** HTTP method used */
  httpMethod: string;
  /** Headers sent with the request */
  headersSent: Record<string, string>;
  /** The dummy payload sent (create/update only) */
  requestBody?: unknown;
  /** Raw response body from the backend */
  responseBody?: unknown;
  /** Human-readable error string for failures */
  errorDetails?: string;
  /** Round-trip time in milliseconds */
  durationMs?: number;
}

/** Tiers that can appear as permission prefixes in legacyRights */
const PERMISSION_TIERS = ['client', 'vendor', 'distributor'] as const;

@Injectable({
  providedIn: 'root',
})
export class ApiSimulationService {
  private readonly http = inject(HttpClient);
  private readonly authData = inject(AuthDataService);
  private readonly apiConfig = inject(Configuration);

  /** Fake UUID used for update/delete path parameters */
  private readonly FAKE_ID = '3fa85f64-5717-4562-b3fc-2c963f66afa6';

  /**
   * Returns ALL API entries from the registry.
   * We test every endpoint — the backend will tell us which are
   * Allowed (200) vs Forbidden (401/403) for the current user.
   */
  getSimulatableApis(): ApiSimulationEntry[] {
    return API_SIMULATION_REGISTRY;
  }

  /**
   * Comprehensive permission check that accounts for the way legacyRights
   * stores permissions:
   *
   * 1. Direct match: `alert:create` exists in the user's permission array
   * 2. Tier-scoped wildcard: `client:alerts` — having the resource name
   *    (without an action) under a parent tier means full CRUD access
   * 3. Tier-scoped specific: `client:list-alerts` — specific action grant
   *
   * @param permission - The registry permission string (e.g., 'alert:create')
   * @param operation - The CRUD operation being tested (list/create/update/delete)
   * @returns true if the user effectively has this permission
   */
  hasEffectivePermission(
    permission: string,
    operation: SimulationOperation,
  ): boolean {
    const realPermissions = this.authData.getRealUserPermissions();

    // Super admin bypass
    if (realPermissions.includes('system:all')) {
      return true;
    }

    // 1. Direct check via the existing mapping logic
    if (this.authData.hasRealPermission(permission)) {
      return true;
    }

    // 2. Parse the permission to get resource and action
    //    e.g., 'alert:create' → resource='alert', action='create'
    const parts = permission.split(':');
    const resource = parts.length >= 2 ? parts[0] : permission;
    const pluralResource = PermissionUtils.getPluralForm(resource);

    // 3. Check tier-scoped wildcard grants: `{tier}:{pluralResource}`
    //    e.g., `client:alerts` = full CRUD on alerts at client level
    for (const tier of PERMISSION_TIERS) {
      if (realPermissions.includes(`${tier}:${pluralResource}`)) {
        return true; // Wildcard = all operations allowed
      }
    }

    // 4. For list operations, also check tier-scoped list grants:
    //    `{tier}:list-{pluralResource}` (e.g., `client:list-alerts`)
    if (operation === 'list') {
      for (const tier of PERMISSION_TIERS) {
        if (realPermissions.includes(`${tier}:list-${pluralResource}`)) {
          return true;
        }
      }
    }

    return false;
  }

  /**
   * Hits the real backend with `x-auth-testing: true` for a single
   * CRUD operation and interprets the response as Allowed / Forbidden / Error.
   */
  async verifyOperation(
    entry: ApiSimulationEntry,
    operation: SimulationOperation,
    ownerId: string,
  ): Promise<SimulationResult> {
    // --- Build URL ---
    const isResourceLevel = operation === 'update' || operation === 'delete';
    let endpointPath = isResourceLevel
      ? `${entry.basePath}/${this.FAKE_ID}`
      : entry.basePath;

    // For list, add query params to limit results
    if (operation === 'list') {
      const separator = endpointPath.includes('?') ? '&' : '?';
      endpointPath = `${endpointPath}${separator}limit=1&owner=${ownerId}`;
    }

    const url = `${this.apiConfig.basePath}${endpointPath}`;

    // --- HTTP method ---
    const httpMethodMap: Record<SimulationOperation, string> = {
      list: 'GET',
      create: 'POST',
      update: 'PUT',
      delete: 'DELETE',
    };
    const httpMethod = httpMethodMap[operation];

    // --- Build payload (list and delete have no body) ---
    const requestBody =
      operation === 'list' || operation === 'delete'
        ? undefined
        : (SmartPayloadBuilder.generateFromRegistry(
            entry,
            operation,
            ownerId,
          ) ?? {});

    // --- Headers ---
    const headersDict: Record<string, string> = {
      'x-auth-testing': 'true',
      'Content-Type': 'application/json',
    };
    const headers = new HttpHeaders(headersDict);
    const context = new HttpContext().set(SILENT_ERROR, true);
    const options = { headers, context, observe: 'response' as const };

    // --- Frontend expectation ---
    // Use comprehensive check that accounts for tier-scoped wildcard/specific grants
    const permissionToCheck =
      operation === 'list' &&
      entry.listPermission !== undefined &&
      entry.listPermission !== ''
        ? entry.listPermission
        : entry.permission;
    const frontendExpected: 'Allowed' | 'Forbidden' =
      this.hasEffectivePermission(permissionToCheck, operation)
        ? 'Allowed'
        : 'Forbidden';

    const startTime = performance.now();

    try {
      let response;
      switch (httpMethod) {
        case 'GET':
          response = await firstValueFrom(this.http.get(url, options));
          break;
        case 'POST':
          response = await firstValueFrom(
            this.http.post(url, requestBody, options),
          );
          break;
        case 'PUT':
          response = await firstValueFrom(
            this.http.put(url, requestBody, options),
          );
          break;
        case 'DELETE':
          response = await firstValueFrom(this.http.delete(url, options));
          break;
      }

      return {
        entry,
        operation,
        frontendExpected,
        backendAccess: 'Allowed',
        url,
        httpMethod,
        headersSent: headersDict,
        requestBody,
        responseBody: response?.body,
        durationMs: Math.round(performance.now() - startTime),
      };
    } catch (err: unknown) {
      return this.buildErrorResult(err, {
        entry,
        operation,
        frontendExpected,
        url,
        httpMethod,
        headersSent: headersDict,
        requestBody,
        startTime,
      });
    }
  }

  /**
   * Parses an error from the HTTP pipeline (which may have been
   * transformed by the auth interceptor) and builds a SimulationResult.
   */
  private buildErrorResult(
    err: unknown,
    ctx: {
      entry: ApiSimulationEntry;
      operation: SimulationOperation;
      frontendExpected: 'Allowed' | 'Forbidden';
      url: string;
      httpMethod: string;
      headersSent: Record<string, string>;
      requestBody: unknown;
      startTime: number;
    },
  ): SimulationResult {
    // The auth interceptor transforms non-401 HttpErrorResponse into plain
    // Error objects with just a message string. We need to detect 403/401
    // from both the original HttpErrorResponse (if it survives) and from
    // the transformed error message.
    let status: number | undefined;
    let errorBody: unknown;
    let errorMessage: string | undefined;

    if (err instanceof HttpErrorResponse) {
      status = err.status;
      errorBody = err.error;
      errorMessage = err.message;
    } else if (err instanceof Error) {
      errorMessage = err.message;
    } else {
      const anyErr = err as Record<string, unknown>;
      status = anyErr['status'] as number | undefined;
      errorBody = anyErr['error'];
      errorMessage = anyErr['message'] as string | undefined;
    }

    const isForbiddenByStatus = status === 403 || status === 401;
    const isForbiddenByMessage =
      errorMessage !== undefined &&
      errorMessage !== '' &&
      (/forbidden/i.test(errorMessage) ||
        /not have permission/i.test(errorMessage) ||
        /unauthorized/i.test(errorMessage));
    const isForbidden = isForbiddenByStatus || isForbiddenByMessage;

    return {
      entry: ctx.entry,
      operation: ctx.operation,
      frontendExpected: ctx.frontendExpected,
      backendAccess: isForbidden ? 'Forbidden' : 'Error',
      url: ctx.url,
      httpMethod: ctx.httpMethod,
      headersSent: ctx.headersSent,
      requestBody: ctx.requestBody,
      responseBody: errorBody ?? undefined,
      durationMs: Math.round(performance.now() - ctx.startTime),
      errorDetails: isForbidden
        ? `${status ?? '403'} Forbidden`
        : `${status ?? 'N/A'} ${errorMessage ?? 'Unknown error'}`,
    };
  }

  /**
   * Runs verification for multiple API entries sequentially.
   * Calls `onProgress` after each individual operation completes.
   */
  async verifyMultiple(
    entries: ApiSimulationEntry[],
    ownerId: string,
    onProgress?: (result: SimulationResult) => void,
  ): Promise<SimulationResult[]> {
    const results: SimulationResult[] = [];

    for (const entry of entries) {
      for (const op of entry.operations) {
        const result = await this.verifyOperation(entry, op, ownerId);
        results.push(result);
        if (onProgress) {
          onProgress(result);
        }
      }
    }

    return results;
  }
}
