import { inject } from '@angular/core';
import { CanActivateFn, Router } from '@angular/router';
import { AuthDataService } from '../services/auth-data.service';

/**
 * Guard that blocks access to admin routes if the user has no permissions assigned.
 * Users with at least one permission (subject to role/tier restrictions) are allowed.
 * Redirects unauthorized users to the /unauthorized page.
 */
export const adminPermissionsGuard: CanActivateFn = () => {
  const authDataService = inject(AuthDataService);
  const router = inject(Router);

  // Check if user has any permissions at all
  if (!authDataService.hasAssignedPermissions()) {
    // User has no permissions, redirect to unauthorized page
    router
      .navigate(['/unauthorized'], {
        queryParams: { reason: 'no_permissions' },
      })
      .catch(() => {});
    return false;
  }

  // User has at least one permission, allow access
  return true;
};
