import { Component, effect, inject, signal, computed } from '@angular/core';
import { CommonModule } from '@angular/common';
import { DynamicDialogConfig, DynamicDialogRef } from 'primeng/dynamicdialog';
import { TabsModule } from 'primeng/tabs';
import { TagModule } from 'primeng/tag';

import { QAToolsService } from '../../../core/services/qa-tools.service';
import { ClientPermissionsService } from '../../../features/administration/services/client-permissions.service';
import { PermissionService } from '../../../core/services/permission.service';
import { CLIENT_ADMIN_FEATURES } from '../../../features/administration/components/clients/client-administration.config';
import { VENDOR_ADMIN_FEATURES } from '../../../features/administration/components/vendors/vendor-administration.config';
import { DISTRIBUTOR_ADMIN_FEATURES } from '../../../features/administration/components/distributors/distributor-administration.config';
import {
  FeatureConfig,
  OwnerType,
  PermissionExpression,
} from '../../../core/models/permission.model';
import { AuthDataService } from '../../../core/services/auth-data.service';
import { isDefined, isNullOrUndefined } from '../../utils';
import {
  ApiVerificationResult,
  ApiVerificationService,
} from '../../../core/services/api-verification.service';

interface FeatureAccessRow {
  featureId: string;
  label: string;
  hasAccess: boolean;
  permissions?: string;
}

/** Valid hierarchical levels for API verification */
type VerificationLevel = 'distributor' | 'vendor' | 'client';

import { QaSimulationTabComponent } from './components/qa-simulation-tab/qa-simulation-tab.component';
import { QaApiVerificationTabComponent } from './components/qa-api-verification-tab/qa-api-verification-tab.component';

@Component({
  selector: 'app-qa-permission-tester',
  imports: [
    CommonModule,
    TagModule,
    TabsModule,
    QaSimulationTabComponent,
    QaApiVerificationTabComponent,
  ],
  templateUrl: './qa-permission-tester.component.html',
  styleUrls: ['./qa-permission-tester.component.scss'],
})
export class QaPermissionTesterComponent {
  readonly qaTools = inject(QAToolsService);
  readonly clientPermissionsService = inject(ClientPermissionsService);
  readonly permissionService = inject(PermissionService);
  readonly authDataService = inject(AuthDataService);
  readonly dialogRef = inject(DynamicDialogRef);
  readonly config = inject(DynamicDialogConfig);
  readonly apiVerificationService = inject(ApiVerificationService);

  // Selected profile for dropdown
  selectedProfileId = signal<string | null>(null);

  // Tab index for the UI
  activeTabIndex = signal<number>(0);

  // Verification state
  verificationResults = signal<ApiVerificationResult[]>([]);
  isVerifying = signal<boolean>(false);
  isSaving = signal<boolean>(false);

  // Filtering and Search
  searchQuery = signal<string>('');
  statusFilter = signal<'all' | 'Allowed' | 'Forbidden' | 'Error' | 'Mismatch'>(
    'all',
  );

  // Statistics
  readonly verificationStats = computed(() => {
    const results = this.verificationResults();
    const total = results.length;
    const allowed = results.filter((r) => r.backendAccess === 'Allowed').length;
    const forbidden = results.filter(
      (r) => r.backendAccess === 'Forbidden',
    ).length;
    const errors = results.filter((r) => r.backendAccess === 'Error').length;
    const mismatches = results.filter(
      (r) => (r.backendAccess === 'Allowed') !== r.frontendExpected,
    ).length;

    return { total, allowed, forbidden, errors, mismatches };
  });

  // Filtered Results
  readonly filteredResults = computed(() => {
    let results = this.verificationResults();
    const query = this.searchQuery().toLowerCase();
    const status = this.statusFilter();

    if (query) {
      results = results.filter(
        (r) =>
          r.endpoint.toLowerCase().includes(query) ||
          r.permission.toLowerCase().includes(query) ||
          r.method.toLowerCase().includes(query),
      );
    }

    if (status !== 'all') {
      if (status === 'Mismatch') {
        results = results.filter(
          (r) => (r.backendAccess === 'Allowed') !== r.frontendExpected,
        );
      } else {
        results = results.filter((r) => r.backendAccess === status);
      }
    }

    return results;
  });

  // Grouped Results
  readonly groupedResults = computed(() => {
    const results = this.filteredResults();
    const groups: Record<string, ApiVerificationResult[]> = {};

    results.forEach((r) => {
      // Extract module from endpoint (e.g., /api/entities -> entities)
      const module = r.endpoint.split('/')[2] || 'other';
      if (isNullOrUndefined(groups[module])) groups[module] = [];
      groups[module].push(r);
    });

    return Object.entries(groups).map(([name, items]) => ({ name, items }));
  });

  // Actual owner type (ignoring QA overrides)
  readonly realOwnerType = computed(
    () => this.authDataService.getRealUserOwnerType() as OwnerType | null,
  );

  // Current owner type (respecting QA overrides)
  readonly ownerType = computed(
    () => this.authDataService.getUserOwnerType() as OwnerType | null,
  );

  // Available roles for dropdown
  readonly roles = this.qaTools.availableRoles;
  readonly isLoading = this.qaTools.isLoadingRoles;

  // Computed access matrices for each admin module
  // These explicitly depend on userPermissions() to update when roles/toggles change
  readonly clientFeatureAccess = computed(() => {
    this.authDataService.userPermissions(); // Track permission changes
    return this.computeFeatureAccess(CLIENT_ADMIN_FEATURES, 'client');
  });

  readonly vendorFeatureAccess = computed(() => {
    this.authDataService.userPermissions(); // Track permission changes
    return this.computeFeatureAccess(VENDOR_ADMIN_FEATURES, 'vendor');
  });

  readonly distributorFeatureAccess = computed(() => {
    this.authDataService.userPermissions(); // Track permission changes
    return this.computeFeatureAccess(DISTRIBUTOR_ADMIN_FEATURES, 'distributor');
  });

  // Permission toggles (scoped to real owner tier)
  readonly togglePermissions = computed(() =>
    this.collectPermissionsByOwner(this.realOwnerType()),
  );

  // Statistics for features
  readonly clientStats = computed(() =>
    this.computeStats(this.clientFeatureAccess()),
  );
  readonly vendorStats = computed(() =>
    this.computeStats(this.vendorFeatureAccess()),
  );
  readonly distributorStats = computed(() =>
    this.computeStats(this.distributorFeatureAccess()),
  );

  // Hierarchical Testing Signals (Exposed from QAToolsService)
  readonly selectedDistributorId = this.qaTools.selectedDistributorId;
  readonly selectedVendorId = this.qaTools.selectedVendorId;
  readonly selectedClientId = this.qaTools.selectedClientId;

  readonly availableDistributors = this.qaTools.availableDistributors;
  readonly availableVendors = this.qaTools.availableVendors;
  readonly availableClients = this.qaTools.availableClients;

  constructor() {
    // Initialize selected persona ID if exists
    const personaValue = this.qaTools.activePersona();
    if (personaValue) {
      this.selectedProfileId.set(personaValue.id);
    }

    // Load available roles on component initialization
    effect(async () => {
      try {
        await this.qaTools.loadAvailableRoles();
        // Also load initial distributors if system user
        if (this.realOwnerType() === 'system') {
          await this.qaTools.loadDistributors();
        } else if (this.realOwnerType() === 'distributor') {
          const ownerId = this.authDataService.getRealUserOwnerId();
          if (ownerId != null && ownerId !== '')
            await this.qaTools.loadVendors(ownerId);
        } else if (this.realOwnerType() === 'vendor') {
          const ownerId = this.authDataService.getRealUserOwnerId();
          if (ownerId != null && ownerId !== '')
            await this.qaTools.loadClients(ownerId);
        }
      } catch (err) {
        console.error('QA Tools: Error loading roles:', err);
      }
    });
  }

  /**
   * Determine whether the current owner can view a given context
   */
  canViewContext(context: OwnerType): boolean {
    const currentOwner = this.realOwnerType();
    const rank: Record<OwnerType, number> = {
      client: 0,
      vendor: 1,
      distributor: 2,
      system: 3,
    };

    if (
      currentOwner === null ||
      !(context in rank) ||
      !(currentOwner in rank)
    ) {
      return false;
    }

    return rank[context] <= rank[currentOwner];
  }

  /**
   * Toggle a permission override
   */
  togglePermission(permission: string, enabled: boolean): void {
    this.qaTools.setPermissionOverride(permission, enabled);
  }

  /**
   * Apply the selected role
   */
  async applyProfile(): Promise<void> {
    const roleId = this.selectedProfileId();
    if (isDefined(roleId)) {
      await this.qaTools.applyRole(roleId);
    }
  }

  /**
   * Reset to real permissions
   */
  resetPermissions(): void {
    this.qaTools.resetQAState();
    this.selectedProfileId.set(null);
  }

  /**
   * Persists current overrides back to the active role
   */
  async saveToRole(): Promise<void> {
    this.isSaving.set(true);
    try {
      await this.qaTools.saveCurrentOverridesToRole();
    } finally {
      this.isSaving.set(false);
    }
  }

  /** Signal for tracking the last level verified */
  readonly lastVerifiedLevel = signal<string | null>(null);

  /**
   * Runs the backend enforcement test suite for a specific level or the default owner.
   */
  async runApiVerification(level?: VerificationLevel): Promise<void> {
    const targetLevel = (level ?? this.realOwnerType()) as OwnerType;

    this.isVerifying.set(true);
    try {
      let targetOwnerId: string | undefined;

      if (level === 'distributor')
        targetOwnerId = this.selectedDistributorId() ?? undefined;
      else if (level === 'vendor')
        targetOwnerId = this.selectedVendorId() ?? undefined;
      else if (level === 'client')
        targetOwnerId = this.selectedClientId() ?? undefined;

      const results =
        await this.apiVerificationService.verifyBackEndEnforcement(
          targetOwnerId,
          targetLevel,
        );

      this.verificationResults.set(results);
      this.lastVerifiedLevel.set(targetLevel);
    } catch (err) {
      console.error('QA Tools: API Verification failed:', err);
    } finally {
      this.isVerifying.set(false);
    }
  }

  /**
   * Close the dialog
   */
  closeDialog(): void {
    this.dialogRef.close();
  }

  /**
   * Get severity for tag based on access
   */
  getAccessSeverity(hasAccess: boolean): 'success' | 'danger' {
    return hasAccess ? 'success' : 'danger';
  }

  /**
   * Get color class for profile badge
   */
  getProfileColorClass(color: string): string {
    const colorMap: Record<string, string> = {
      green: 'bg-green-500',
      blue: 'bg-blue-500',
      orange: 'bg-orange-500',
      red: 'bg-red-500',
      purple: 'bg-purple-500',
      gray: 'bg-gray-500',
    };
    return colorMap[color] || 'bg-gray-500';
  }

  /**
   * Compute feature access for a given admin features config
   */
  private computeFeatureAccess(
    featuresConfig: Record<string, FeatureConfig>,
    context: 'client' | 'vendor' | 'distributor',
  ): FeatureAccessRow[] {
    return Object.entries(featuresConfig).map(([featureId, config]) => {
      const hasAccess = this.checkFeatureAccess(config, context);
      return {
        featureId,
        label: config.label,
        hasAccess,
        permissions: this.formatPermissions(config),
      };
    });
  }

  /**
   * Check if current profile has access to a feature
   *
   * Handles special cases:
   * - If persona has no permissions (empty array), nothing is accessible
   * - system:all grants access to all features
   * - Features with no permission requirements are always accessible
   * - Evaluates permission expressions directly against current permissions
   */
  private checkFeatureAccess(
    config: FeatureConfig,
    _context: 'client' | 'vendor' | 'distributor',
  ): boolean {
    if (!('permissions' in config)) {
      return true; // No permissions required
    }

    const permissions = config.permissions;
    if (permissions === null || permissions === undefined) {
      return true;
    }

    // Get current permissions from QA override
    const currentPermissions = this.authDataService.userPermissions();

    // If no permissions assigned and feature requires permissions, deny access
    if (currentPermissions.length === 0) {
      return false;
    }

    // system:all grants access to everything
    if (currentPermissions.includes('system:all')) {
      return true;
    }

    // Directly evaluate permission expression against current permissions
    return this.evaluatePermissionExpression(permissions, currentPermissions);
  }

  /**
   * Evaluate a permission expression against the current permission set
   */
  private evaluatePermissionExpression(
    expression: PermissionExpression,
    permissions: string[],
  ): boolean {
    const permissionSet = new Set(permissions);

    // String permission
    if (typeof expression === 'string') {
      return permissionSet.has(expression);
    }

    // Array of strings (AND logic - all required)
    if (Array.isArray(expression)) {
      return expression.every((perm) => permissionSet.has(perm));
    }

    // Query object (complex logic: and, or, not)
    if (typeof expression === 'object' && expression !== null) {
      const query = expression as Record<string, unknown>;

      // AND logic - all conditions must be true
      if ('and' in query && Array.isArray(query['and'])) {
        return (query['and'] as PermissionExpression[]).every((cond) =>
          this.evaluatePermissionExpression(cond, permissions),
        );
      }

      // OR logic - at least one condition must be true
      if ('or' in query && Array.isArray(query['or'])) {
        return (query['or'] as PermissionExpression[]).some((cond) =>
          this.evaluatePermissionExpression(cond, permissions),
        );
      }

      // NOT logic - condition must be false
      if ('not' in query && query['not'] !== undefined) {
        return !this.evaluatePermissionExpression(
          query['not'] as PermissionExpression,
          permissions,
        );
      }
    }

    return false;
  }

  /**
   * Format permissions for display
   */
  private formatPermissions(config: FeatureConfig): string {
    if (!('permissions' in config)) {
      return 'No permissions required';
    }

    const perms = config.permissions;
    if (perms === null || perms === undefined) {
      return 'No permissions required';
    }

    if (typeof perms === 'string') {
      return perms;
    } else if (Array.isArray(perms)) {
      return perms.join(', ');
    } else {
      return JSON.stringify(perms);
    }
  }

  /**
   * Compute statistics for feature access
   */
  private computeStats(features: FeatureAccessRow[]): {
    total: number;
    accessible: number;
    restricted: number;
  } {
    const total = features.length;
    const accessible = features.filter((f) => f.hasAccess).length;
    const restricted = total - accessible;
    return { total, accessible, restricted };
  }

  private collectPermissionsByOwner(ownerType: OwnerType | null): string[] {
    if (!ownerType) {
      return [];
    }

    const permissions = new Set<string>();
    const contexts: {
      config: Record<string, FeatureConfig>;
      type: OwnerType;
    }[] = [
      { config: CLIENT_ADMIN_FEATURES, type: 'client' },
      { config: VENDOR_ADMIN_FEATURES, type: 'vendor' },
      { config: DISTRIBUTOR_ADMIN_FEATURES, type: 'distributor' },
    ];

    for (const context of contexts) {
      if (!this.canViewContext(context.type)) {
        continue;
      }

      const extracted = this.extractPermissionsFromConfig(context.config);
      for (const permission of extracted) {
        permissions.add(permission);
      }
    }

    return [...permissions].sort((a, b) => a.localeCompare(b));
  }

  private extractPermissionsFromConfig(
    config: Record<string, FeatureConfig>,
  ): string[] {
    const permissions: string[] = [];
    for (const feature of Object.values(config)) {
      const permissionsValue =
        'permissions' in feature ? feature.permissions : undefined;
      if (permissionsValue !== null && permissionsValue !== undefined) {
        permissions.push(...this.flattenPermissions(permissionsValue));
      }
    }
    return permissions;
  }

  private flattenPermissions(expression: PermissionExpression): string[] {
    if (typeof expression === 'string') {
      return [expression];
    }

    if (Array.isArray(expression)) {
      return expression.flatMap((value) => this.flattenPermissions(value));
    }

    const permissions: string[] = [];
    if (isDefined(expression.and)) {
      permissions.push(
        ...expression.and.flatMap((value: PermissionExpression) =>
          this.flattenPermissions(value),
        ),
      );
    }
    if (isDefined(expression.or)) {
      permissions.push(
        ...expression.or.flatMap((value: PermissionExpression) =>
          this.flattenPermissions(value),
        ),
      );
    }
    if (isDefined(expression.not)) {
      permissions.push(...this.flattenPermissions(expression.not));
    }

    return permissions;
  }
}
